SET FOREIGN_KEY_CHECKS = 0;
DROP TABLE IF EXISTS user_auth;
DROP TABLE IF EXISTS user;
DROP TABLE IF EXISTS cart;
DROP TABLE IF EXISTS book;
DROP TABLE IF EXISTS orders;
DROP TABLE IF EXISTS order_items;
SET FOREIGN_KEY_CHECKS = 1;
-- 创建book表
CREATE TABLE IF NOT EXISTS book (
  id BIGINT AUTO_INCREMENT PRIMARY KEY,
  title VARCHAR(255) NOT NULL,
  author VARCHAR(100) NOT NULL,
  price DECIMAL(10,2) NOT NULL,
  cover LONGTEXT,
  description TEXT,
  isbn VARCHAR(20),
  stock INT DEFAULT 0 COMMENT '库存量',
  publisher TEXT COMMENT '出版社',
  deleted BOOLEAN NOT NULL DEFAULT FALSE COMMENT '软删除标识，true表示已删除'
);



-- 插入图书数据
INSERT INTO book (title, author, price, isbn, stock, publisher, cover, description) VALUES
('CSAPP: 深入理解计算机系统', 'Randal E. Bryant, David R. O Hallaron', 130.0,'978-7-5455-5388-8',10000, '上海交通大学出版社', 'data:image/jpeg;base64,', '本书是计算机科学领域的里程碑式著作，被全球多所顶尖大学选为教材。它不仅仅罗列知识点，更强调从程序员的视角来理解计算机系统如何工作，以及这些知识如何影响程序的正确性、性能和健壮性。内容覆盖信息表示（如浮点数）、处理器体系结构、汇编语言、存储器层次结构、链接、虚拟内存、系统级I/O、网络编程（如套接字接口）和并发编程（如线程）。通过大量的示例和实践性的实验（Labs），帮助读者将理论与实践相结合，为编写高效、可靠的软件打下坚实的基础。'),
('算法导论', 'Thomas H. Cormen, Charles E. Leiserson, Ronald L. Rivest, Clifford Stein', 118.0, '978-7-5455-5388-8',10000, '上海交通大学出版社','data:image/jpeg;base64,', '作为算法领域最权威、最全面的著作之一，本书覆盖了现代算法研究和应用的方方面面。它以严谨的数学语言精确描述算法，并深入分析其效率。内容涵盖了基础数据结构（如链表、树、散列表）、高级设计和分析技术（如分治、动态规划、贪心算法）、图算法（如最短路径、最大流）、计算几何、数论算法、字符串匹配以及并行计算等。书中包含大量的习题和思考题，适合计算机专业的学生、研究人员以及需要解决复杂计算问题的工程师深入学习和参考。'),
('代码整洁之道', 'Robert C. Martin', 59.0, '978-7-5455-5388-8',10000, '上海交通大学出版社','data:image/jpeg;base64,', '软件开发大师“Bob大叔”的经典之作，它不仅仅是关于如何写出能工作的代码，更是关于如何写出易于阅读、理解和维护的“整洁”代码。书中详细阐述了代码整洁的重要性，揭示了混乱代码带来的巨大成本。作者结合具体的代码示例，系统地介绍了命名规范、函数设计原则（如短小、单一职责）、注释的恰当使用、代码格式化、对象和数据结构、错误处理的最佳实践、单元测试以及识别和清理“代码坏味”（Code Smells）的方法。本书是提升软件工艺和职业素养的必读指南。'),
('设计模式', 'Erich Gamma, Richard Helm, Ralph Johnson, John Vlissides', 79.0, '978-7-5455-5388-8',10000, '上海交通大学出版社','data:image/jpeg;base64,', '这本由“四人帮”（Gang of Four, GoF）合著的著作是面向对象设计领域的不朽经典。它首次系统化地总结并命名了23种经过实践检验、可复用的设计模式，并将其分为创建型（如工厂方法、单例）、结构型（如适配器、装饰器）和行为型（如策略、观察者）三类。每种模式都阐述了其意图、动机、适用性、结构、实现、效果以及相关的已知应用。学习设计模式有助于开发者提高代码的灵活性、可扩展性和可维护性，并能更有效地与同行交流设计思想，是提升软件设计能力的关键读物。'),
('JavaScript高级程序设计', 'Nicholas C. Zakas, Matt Frisbie', 99.0, '978-7-5455-5388-8',10000, '上海交通大学出版社','data:image/jpeg;base64,', '作为JavaScript领域的权威参考书之一（俗称“红宝书”），本书全面深入地探讨了JavaScript语言的核心概念和Web开发中的应用。内容不仅涵盖了基础语法、变量、作用域、闭包、原型链、继承机制等语言精髓，还详细讲解了DOM操作、事件模型、浏览器对象模型（BOM）、Ajax与Fetch API、客户端存储、性能优化等Web开发关键技术。书中还紧随技术发展，介绍了最新的ECMAScript标准特性，如Promise、async/await、类、模块等。对于希望系统掌握JavaScript并成为专业前端开发者的读者来说，本书提供了扎实且全面的知识体系。'),
('Python编程：从入门到实践', 'Eric Matthes', 89.0, '978-7-5455-5388-8',10000, '上海交通大学出版社','data:image/jpeg;base64,', '这是一本极受欢迎的Python入门书籍，特别适合编程初学者。本书结构清晰，分为两大部分。第一部分系统讲解Python的基础知识，包括变量、数据类型、列表、字典、循环、函数、类、文件操作和测试等核心概念，语言通俗易懂。第二部分的精华在于通过三个引人入胜的实战项目——开发一个名为“外星人入侵”的Pygame游戏、利用matplotlib和Plotly进行数据可视化分析、以及使用Django框架构建一个简单的Web应用程序——让读者在实践中巩固所学知识，体验编程的乐趣和应用价值。'),
('黑客与画家', 'Paul Graham', 49.0,'978-7-5455-5388-8',10000, '上海交通大学出版社', 'data:image/jpeg;base64,', '本书是硅谷创业教父、Y Combinator创始人Paul Graham的文集精选，充满了智慧与洞见。作者以其独特的程序员和创业者视角，探讨了计算机科学、技术创新、编程语言（尤其是Lisp）、创业文化、财富创造以及社会现象等广泛议题。书中包含了诸如“为什么书呆子不受欢迎”、“创造财富”、“设计者的品味”等著名篇章，挑战传统思维，揭示了“黑客”精神与创造性工作的共通之处。其深刻的思考和风趣的文笔，对于程序员、创业者以及任何对技术和创新感兴趣的人都极具启发性。'),
('人月神话', 'Frederick P. Brooks Jr.', 68.0, '978-7-5455-5388-8',10000, '上海交通大学出版社','data:image/jpeg;base64,', '尽管首次出版于几十年前，本书依然是软件工程和项目管理领域难以逾越的经典。作者Brooks基于其领导IBM System/360大型操作系统项目的宝贵经验，提出了一系列关于软件开发复杂性的深刻见解。其中最著名的莫过于“布鲁克斯定律”：向进度落后的软件项目中增加人手只会使项目进一步延误。书中还探讨了概念完整性的重要性、外科手术式团队的理念、文档的作用、以及“没有银弹”等至今仍极具现实意义的论断。对于任何参与软件开发或管理的人来说，本书都提供了永恒的智慧和警示。'),
('活着', '余华', 28.0, '978-7-5455-5388-8',10000, '上海交通大学出版社','data:image/jpeg;base64,', '作为中国当代文学的重要代表作，余华的《活着》以一种近乎残酷的冷静和朴实，讲述了主人公徐福贵在跨越数十年的中国历史巨变（从内战、土地改革到大跃进、文化大革命）中饱经沧桑的一生。小说通过福贵不断失去亲人的悲惨遭遇，展现了个人命运在时代洪流下的渺小与无常，以及普通人在极端苦难面前所能爆发出的惊人韧性。它并非聚焦于控诉，而是深刻地探讨了生命的意义——仅仅是“活着”本身，就蕴含着一种强大的力量。这部作品以其深刻的人性关怀和震撼人心的力量感动了无数读者。'),
('三体', '刘慈欣', 48.0, '978-7-5455-5388-8',10000, '上海交通大学出版社','data:image/jpeg;base64,', '这是刘慈欣创作的宏伟科幻史诗“地球往事”三部曲的第一部，也是亚洲首部获得世界科幻文学最高奖“雨果奖”的作品。小说以其极其宏大的想象力和硬核的科学设定，讲述了地球文明在收到来自濒临毁灭的三体星系的信号后，两个文明之间展开的殊死博弈。书中引入了诸如“三体问题”、“智子”、“面壁计划”、“黑暗森林法则”等令人震撼的科幻概念，不仅构建了一个波澜壮阔的宇宙图景，更深入探讨了关于文明生存、宇宙社会学、技术伦理以及人性的终极问题，极大地提升了中国科幻文学在世界上的影响力。'),
('追风筝的人', '卡勒德·胡赛尼', 36.0, '978-7-5455-5388-8',10000, '上海交通大学出版社','data:image/jpeg;base64,', '这部在全球范围内引起广泛共鸣的小说，以第一人称视角讲述了阿富汗富家少爷阿米尔的成长故事。故事的核心围绕着他与仆人哈桑之间复杂而脆弱的友谊，以及童年时期一次关键的背叛行为所带来的终生内疚。小说背景跨越了阿富汗从君主制到苏联入侵，再到塔利班统治的动荡历史时期，深刻揭示了战争、种族歧视（普什图人与哈扎拉人）和社会动荡对个人命运的残酷影响。最终，阿米尔踏上了艰难的自我救赎之路，回到了故土。这是一个关于罪责、亲情、勇气和人性救赎的感人故事。'),
('白夜行', '东野圭吾', 45.0, '978-7-5455-5388-8',10000, '上海交通大学出版社','data:image/jpeg;base64,', '作为日本推理小说大师东野圭吾的代表作之一，《白夜行》以其独特的叙事结构和深刻的人性探讨而著称。故事时间跨度长达19年，围绕着一对童年遭遇不幸、似乎有着某种共生关系的男女主人公——桐原亮司和西本雪穗展开。小说极少直接描写两人的内心活动和直接关联，而是通过一系列看似无关的案件和旁人的视角，逐渐勾勒出他们之间隐藏的黑暗秘密和扭曲的情感。这种“无光”的叙事手法营造出一种压抑、绝望的氛围，让读者在探寻真相的同时，也对人性的复杂与黑暗面进行深刻反思。'),
('小王子', '安托万·德·圣埃克苏佩里', 22.0,'978-7-5455-5388-8',10000, '上海交通大学出版社', 'data:image/jpeg;base64,', '这部看似写给儿童、实则蕴含深刻哲理的经典童话，是法国作家圣埃克苏佩里的传世之作。故事讲述了一位迫降在撒哈拉沙漠的飞行员，遇到了来自B-612小行星的小王子。通过小王子讲述他拜访各个星球（住着国王、爱慕虚荣的人、酒鬼、商人、点灯人、地理学家）的经历，以及他与一朵玫瑰花和一只狐狸的故事，小说以纯真诗意的语言探讨了友谊、爱情、责任、失去以及成人世界的僵化与盲目。它提醒我们勿忘童心，珍视那些生命中真正重要的、眼睛看不见的东西。'),
('围城', '钱钟书', 39.0, '978-7-5455-5388-8',10000, '上海交通大学出版社','data:image/jpeg;base64,', '钱钟书先生的《围城》是中国现代文学史上的一部 satirical masterpiece (讽刺杰作)。小说以留洋归来的方鸿渐为中心，描绘了他在爱情、婚姻、事业和人际关系中的种种遭遇和困境。通过对方鸿渐及围绕在他身边的知识分子群体的细致刻画，小说对上世纪三四十年代中国社会的弊病、知识界的虚伪、婚姻的困局（借用著名比喻：“城外的人想冲进去，城里的人想逃出来”）进行了入木三分的讽刺和揭示。其语言机智幽默，充满警句格言，对人性弱点的洞察极为深刻，至今仍能引发读者的强烈共鸣。'),
('挪威的森林', '村上春树', 38.0, '978-7-5455-5388-8',10000, '上海交通大学出版社','data:image/jpeg;base64,', '这是日本当代著名作家村上春树最具影响力的作品之一，是一部充满青春感伤、迷惘与怀旧气息的现实主义爱情小说。故事背景设定在日本1960年代末学运风潮时期，主人公渡边彻以第一人称回忆了自己大学时代纠缠在两位性格截然不同的女性之间的经历：一位是精神脆弱、沉湎于过去悲伤的直子，另一位是活泼开朗、充满生命力的绿子。小说细腻地描摹了年轻人在成长过程中的孤独、性爱、死亡阴影、以及对爱情和人生意义的探索。其独特的感性笔触和忧郁氛围使其成为一代人的青春读本。'),
('百年孤独', '加西亚·马尔克斯', 55.0, '978-7-5455-5388-8',10000, '上海交通大学出版社','data:image/jpeg;base64,', '哥伦比亚文豪、诺贝尔文学奖得主加西亚·马尔克斯的代表作，《百年孤独》是魔幻现实主义文学的巅峰之作。这部鸿篇巨著讲述了布恩迪亚家族七代人在虚构小镇马孔多的传奇兴衰史，时间跨度超过百年。小说将离奇的幻想（如幽灵、预言、飞毯、不眠症瘟疫、美女蕾梅黛丝升天）与残酷的现实（如内战、香蕉公司屠杀、社会变迁）无缝编织在一起，创造出一个光怪陆离、引人入胜的世界。它深刻地探讨了拉丁美洲的历史循环、孤独的主题、时间的破坏力以及人性的复杂，是世界文学史上不可磨灭的丰碑。');



-- 创建user表 
CREATE TABLE IF NOT EXISTS user (
  id BIGINT AUTO_INCREMENT PRIMARY KEY,
  name VARCHAR(50) NOT NULL,
  email VARCHAR(100) NOT NULL UNIQUE,
  phone VARCHAR(20),
  address TEXT,
  account VARCHAR(50) NOT NULL UNIQUE,
  role ENUM('user', 'admin') DEFAULT 'user',
  status ENUM('active', 'disabled') DEFAULT 'active',
  balance DECIMAL(10,2) DEFAULT 100000.00
);


-- 创建user_auth表
CREATE TABLE IF NOT EXISTS user_auth (
  id BIGINT AUTO_INCREMENT PRIMARY KEY,
  account VARCHAR(50) NOT NULL UNIQUE,
  password VARCHAR(100) NOT NULL,
  FOREIGN KEY (account) REFERENCES user(account) ON DELETE CASCADE
);

